605 /// Creates a VPWidenIntOrFpInductionRecipe or VPWidenPointerInductionRecipe
606 /// for \p Phi based on \p IndDesc.
607 static VPHeaderPHIRecipe *
608 createWidenInductionRecipe(PHINode *Phi, VPPhi *PhiR, VPIRValue *Start,
609                            const InductionDescriptor &IndDesc, VPlan &Plan,
610                            PredicatedScalarEvolution &PSE, Loop &OrigLoop,
611                            DebugLoc DL) {
612   [[maybe_unused]] ScalarEvolution &SE = *PSE.getSE();
613   assert(SE.isLoopInvariant(IndDesc.getStep(), &OrigLoop) &&
614          "step must be loop invariant");
615   assert((Plan.getLiveIn(IndDesc.getStartValue()) == Start ||
616           (SE.isSCEVable(IndDesc.getStartValue()->getType()) &&
617            SE.getSCEV(IndDesc.getStartValue()) ==
618                vputils::getSCEVExprForVPValue(Start, PSE))) &&
619          "Start VPValue must match IndDesc's start value");
620 
621   VPValue *Step =
622       vputils::getOrCreateVPValueForSCEVExpr(Plan, IndDesc.getStep());
623 
624   if (IndDesc.getKind() == InductionDescriptor::IK_PtrInduction)
625     return new VPWidenPointerInductionRecipe(Phi, Start, Step, &Plan.getVFxUF(),
626                                              IndDesc, DL);
627 
628   assert((IndDesc.getKind() == InductionDescriptor::IK_IntInduction ||
629           IndDesc.getKind() == InductionDescriptor::IK_FpInduction) &&
630          "must have an integer or float induction at this point");
631 
632   // Update wide induction increments to use the same step as the corresponding
633   // wide induction. This enables detecting induction increments directly in
634   // VPlan and removes redundant splats.
635   using namespace llvm::VPlanPatternMatch;
636   if (match(PhiR->getOperand(1), m_Add(m_Specific(PhiR), m_VPValue())))
637     PhiR->getOperand(1)->getDefiningRecipe()->setOperand(1, Step);
638 
639   // It is always safe to copy over the NoWrap and FastMath flags. In
640   // particular, when folding tail by masking, the masked-off lanes are never
641   // used, so it is safe.
642   VPIRFlags Flags = vputils::getFlagsFromIndDesc(IndDesc);
643 
644   return new VPWidenIntOrFpInductionRecipe(Phi, Start, Step, &Plan.getVF(),
645                                            IndDesc, Flags, DL);
646 }
