648 void VPlanTransforms::createHeaderPhiRecipes(
649     VPlan &Plan, PredicatedScalarEvolution &PSE, Loop &OrigLoop,
650     const MapVector<PHINode *, InductionDescriptor> &Inductions,
651     const MapVector<PHINode *, RecurrenceDescriptor> &Reductions,
652     const SmallPtrSetImpl<const PHINode *> &FixedOrderRecurrences,
653     const SmallPtrSetImpl<PHINode *> &InLoopReductions, bool AllowReordering) {
654   // Retrieve the header manually from the intial plain-CFG VPlan.
655   VPBasicBlock *HeaderVPBB = cast<VPBasicBlock>(
656       Plan.getEntry()->getSuccessors()[1]->getSingleSuccessor());
657   assert(VPDominatorTree(Plan).dominates(HeaderVPBB,
658                                          HeaderVPBB->getPredecessors()[1]) &&
659          "header must dominate its latch");
660 
661   auto CreateHeaderPhiRecipe = [&](VPPhi *PhiR) -> VPHeaderPHIRecipe * {
662     // TODO: Gradually replace uses of underlying instruction by analyses on
663     // VPlan.
664     auto *Phi = cast<PHINode>(PhiR->getUnderlyingInstr());
665     assert(PhiR->getNumOperands() == 2 &&
666            "Must have 2 operands for header phis");
667 
668     // Extract common values once.
669     VPIRValue *Start = cast<VPIRValue>(PhiR->getOperand(0));
670     VPValue *BackedgeValue = PhiR->getOperand(1);
671 
672     if (FixedOrderRecurrences.contains(Phi)) {
673       // TODO: Currently fixed-order recurrences are modeled as chains of
674       // first-order recurrences. If there are no users of the intermediate
675       // recurrences in the chain, the fixed order recurrence should be
676       // modeled directly, enabling more efficient codegen.
677       return new VPFirstOrderRecurrencePHIRecipe(Phi, *Start, *BackedgeValue);
678     }
679 
680     auto InductionIt = Inductions.find(Phi);
681     if (InductionIt != Inductions.end())
682       return createWidenInductionRecipe(Phi, PhiR, Start, InductionIt->second,
683                                         Plan, PSE, OrigLoop,
684                                         PhiR->getDebugLoc());
685 
686     assert(Reductions.contains(Phi) && "only reductions are expected now");
687     const RecurrenceDescriptor &RdxDesc = Reductions.lookup(Phi);
688     assert(RdxDesc.getRecurrenceStartValue() ==
689                Phi->getIncomingValueForBlock(OrigLoop.getLoopPreheader()) &&
690            "incoming value must match start value");
691     // Will be updated later to >1 if reduction is partial.
692     unsigned ScaleFactor = 1;
693     bool UseOrderedReductions = !AllowReordering && RdxDesc.isOrdered();
694     return new VPReductionPHIRecipe(
695         Phi, RdxDesc.getRecurrenceKind(), *Start, *BackedgeValue,
696         getReductionStyle(InLoopReductions.contains(Phi), UseOrderedReductions,
697                           ScaleFactor),
698         RdxDesc.hasUsesOutsideReductionChain());
699   };
700 
701   for (VPRecipeBase &R : make_early_inc_range(HeaderVPBB->phis())) {
702     if (isa<VPCanonicalIVPHIRecipe>(&R))
703       continue;
704     auto *PhiR = cast<VPPhi>(&R);
705     VPHeaderPHIRecipe *HeaderPhiR = CreateHeaderPhiRecipe(PhiR);
706     HeaderPhiR->insertBefore(PhiR);
707     PhiR->replaceAllUsesWith(HeaderPhiR);
708     PhiR->eraseFromParent();
709   }
710 }
