712 void VPlanTransforms::createInLoopReductionRecipes(
713     VPlan &Plan, const DenseMap<VPBasicBlock *, VPValue *> &BlockMaskCache,
714     const DenseSet<BasicBlock *> &BlocksNeedingPredication,
715     ElementCount MinVF) {
716   VPTypeAnalysis TypeInfo(Plan);
717   VPBasicBlock *Header = Plan.getVectorLoopRegion()->getEntryBasicBlock();
718   SmallVector<VPRecipeBase *> ToDelete;
719 
720   for (VPRecipeBase &R : Header->phis()) {
721     auto *PhiR = dyn_cast<VPReductionPHIRecipe>(&R);
722     if (!PhiR || !PhiR->isInLoop() || (MinVF.isScalar() && !PhiR->isOrdered()))
723       continue;
724 
725     RecurKind Kind = PhiR->getRecurrenceKind();
726     assert(!RecurrenceDescriptor::isFindLastRecurrenceKind(Kind) &&
727            !RecurrenceDescriptor::isAnyOfRecurrenceKind(Kind) &&
728            !RecurrenceDescriptor::isFindIVRecurrenceKind(Kind) &&
729            "AnyOf and Find reductions are not allowed for in-loop reductions");
730 
731     bool IsFPRecurrence =
732         RecurrenceDescriptor::isFloatingPointRecurrenceKind(Kind);
733     FastMathFlags FMFs =
734         IsFPRecurrence ? FastMathFlags::getFast() : FastMathFlags();
735 
736     // Collect the chain of "link" recipes for the reduction starting at PhiR.
737     SetVector<VPSingleDefRecipe *> Worklist;
738     Worklist.insert(PhiR);
739     for (unsigned I = 0; I != Worklist.size(); ++I) {
740       VPSingleDefRecipe *Cur = Worklist[I];
741       for (VPUser *U : Cur->users()) {
742         auto *UserRecipe = cast<VPSingleDefRecipe>(U);
743         if (!UserRecipe->getParent()->getEnclosingLoopRegion()) {
744           assert((UserRecipe->getParent() == Plan.getMiddleBlock() ||
745                   UserRecipe->getParent() == Plan.getScalarPreheader()) &&
746                  "U must be either in the loop region, the middle block or the "
747                  "scalar preheader.");
748           continue;
749         }
750 
751         // Stores using instructions will be sunk later.
752         if (match(UserRecipe, m_VPInstruction<Instruction::Store>()))
753           continue;
754         Worklist.insert(UserRecipe);
755       }
756     }
757 
758     // Visit operation "Links" along the reduction chain top-down starting from
759     // the phi until LoopExitValue. We keep track of the previous item
760     // (PreviousLink) to tell which of the two operands of a Link will remain
761     // scalar and which will be reduced. For minmax by select(cmp), Link will be
762     // the select instructions. Blend recipes of in-loop reduction phi's will
763     // get folded to their non-phi operand, as the reduction recipe handles the
764     // condition directly.
765     VPSingleDefRecipe *PreviousLink = PhiR; // Aka Worklist[0].
766     for (VPSingleDefRecipe *CurrentLink : drop_begin(Worklist)) {
767       if (auto *Blend = dyn_cast<VPBlendRecipe>(CurrentLink)) {
768         assert(Blend->getNumIncomingValues() == 2 &&
769                "Blend must have 2 incoming values");
770         unsigned PhiRIdx = Blend->getIncomingValue(0) == PhiR ? 0 : 1;
771         assert(Blend->getIncomingValue(PhiRIdx) == PhiR &&
772                "PhiR must be an operand of the blend");
773         Blend->replaceAllUsesWith(Blend->getIncomingValue(1 - PhiRIdx));
774         continue;
775       }
776 
777       if (IsFPRecurrence) {
778         FastMathFlags CurFMF =
779             cast<VPRecipeWithIRFlags>(CurrentLink)->getFastMathFlags();
780         if (match(CurrentLink, m_Select(m_VPValue(), m_VPValue(), m_VPValue())))
781           CurFMF |= cast<VPRecipeWithIRFlags>(CurrentLink->getOperand(0))
782                         ->getFastMathFlags();
783         FMFs &= CurFMF;
784       }
785 
786       Instruction *CurrentLinkI = CurrentLink->getUnderlyingInstr();
787 
788       // Recognize a call to the llvm.fmuladd intrinsic.
789       bool IsFMulAdd = Kind == RecurKind::FMulAdd;
790       VPValue *VecOp;
791       VPBasicBlock *LinkVPBB = CurrentLink->getParent();
792       if (IsFMulAdd) {
793         assert(RecurrenceDescriptor::isFMulAddIntrinsic(CurrentLinkI) &&
794                "Expected current VPInstruction to be a call to the "
795                "llvm.fmuladd intrinsic");
796         assert(CurrentLink->getOperand(2) == PreviousLink &&
797                "expected a call where the previous link is the added operand");
798 
799         // If the instruction is a call to the llvm.fmuladd intrinsic then we
800         // need to create an fmul recipe (multiplying the first two operands of
801         // the fmuladd together) to use as the vector operand for the fadd
802         // reduction.
803         auto *FMulRecipe = new VPInstruction(
804             Instruction::FMul,
805             {CurrentLink->getOperand(0), CurrentLink->getOperand(1)},
806             CurrentLinkI->getFastMathFlags());
807         LinkVPBB->insert(FMulRecipe, CurrentLink->getIterator());
808         VecOp = FMulRecipe;
809       } else if (Kind == RecurKind::AddChainWithSubs &&
810                  match(CurrentLink, m_Sub(m_VPValue(), m_VPValue()))) {
811         Type *PhiTy = TypeInfo.inferScalarType(PhiR);
812         auto *Zero = Plan.getConstantInt(PhiTy, 0);
813         auto *Sub = new VPInstruction(Instruction::Sub,
814                                       {Zero, CurrentLink->getOperand(1)}, {},
815                                       {}, CurrentLinkI->getDebugLoc());
816         Sub->setUnderlyingValue(CurrentLinkI);
817         LinkVPBB->insert(Sub, CurrentLink->getIterator());
818         VecOp = Sub;
819       } else {
820         // Index of the first operand which holds a non-mask vector operand.
821         unsigned IndexOfFirstOperand = 0;
822         if (RecurrenceDescriptor::isMinMaxRecurrenceKind(Kind)) {
823           if (match(CurrentLink, m_Cmp(m_VPValue(), m_VPValue())))
824             continue;
825           assert(match(CurrentLink,
826                        m_Select(m_VPValue(), m_VPValue(), m_VPValue())) &&
827                  "must be a select recipe");
828           IndexOfFirstOperand = 1;
829         }
